/**
 * @name Taint flow from remote input to OS command execution
 * @description Detects user-controlled input reaching Runtime.exec() or ProcessBuilder
 * @kind path-problem
 * @problem.severity error
 * @id java/os-command-injection-cps
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module CmdInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // Runtime.exec(String) - single string form (shell-interpreted)
    exists(MethodCall mc |
      mc.getMethod().hasName("exec") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "Runtime") and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // ProcessBuilder constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = ce.getAnArgument()
    )
    or
    // ProcessBuilder.command()
    exists(MethodCall mc |
      mc.getMethod().hasName("command") and
      mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

module CmdInjectionFlow = TaintTracking::Global<CmdInjectionConfig>;
import CmdInjectionFlow::PathGraph

from CmdInjectionFlow::PathNode source, CmdInjectionFlow::PathNode sink
where CmdInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "OS command injection: data flows from $@ to command execution.", source.getNode(), "remote input"

/**
 * @name Groovy script execution with user-controlled content
 * @description Detects user-controlled input reaching Groovy script evaluation
 * @kind path-problem
 * @problem.severity error
 * @id java/groovy-injection-cps
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module GroovyInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // GroovyShell.evaluate/parse/run
    exists(MethodCall mc |
      mc.getMethod().hasName(["evaluate", "parse", "run", "runScript"]) and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyShell") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // ScriptEngine.eval
    exists(MethodCall mc |
      mc.getMethod().hasName("eval") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.script", "ScriptEngine") and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // GroovyClassLoader.parseClass
    exists(MethodCall mc |
      mc.getMethod().hasName("parseClass") and
      mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyClassLoader") and
      sink.asExpr() = mc.getArgument(0)
    )
  }
}

module GroovyInjectionFlow = TaintTracking::Global<GroovyInjectionConfig>;
import GroovyInjectionFlow::PathGraph

from GroovyInjectionFlow::PathNode source, GroovyInjectionFlow::PathNode sink
where GroovyInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Groovy script injection: data flows from $@ to script evaluation.", source.getNode(), "remote input"

/**
 * @name ReplayAction doRun HTTP parameter flow to Groovy execution
 * @description Traces HTTP request parameters in ReplayAction.doRun to script execution
 * @kind path-problem
 * @problem.severity error
 * @id java/replay-action-injection
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module ReplayInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // HTTP request parameters from StaplerRequest
    exists(MethodCall mc |
      mc.getMethod().hasName(["getParameter", "getSubmittedForm", "bindJSON", "bindParametersToProperties"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("org.kohsuke.stapler", "StaplerRequest") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("javax.servlet.http", "HttpServletRequest")
      ) and
      source.asExpr() = mc
    )
    or
    // Parameters of doRun and run methods in ReplayAction
    exists(Parameter p |
      p.getCallable().getDeclaringType().hasName("ReplayAction") and
      p.getCallable().hasName(["doRun", "run"]) and
      source.asParameter() = p
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // GroovyShell parse/evaluate
    exists(MethodCall mc |
      mc.getMethod().hasName(["evaluate", "parse", "run", "runScript", "parseClass"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyShell") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyClassLoader")
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // CpsFlowDefinition constructor (script field)
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasName("CpsFlowDefinition") and
      sink.asExpr() = ce.getArgument(0)
    )
  }
}

module ReplayInjectionFlow = TaintTracking::Global<ReplayInjectionConfig>;
import ReplayInjectionFlow::PathGraph

from ReplayInjectionFlow::PathNode source, ReplayInjectionFlow::PathNode sink
where ReplayInjectionFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Script injection: data flows from $@ to Groovy execution.", source.getNode(), "HTTP input"

