/**
 * @name doCheckScriptCompile uses trusted shell with user input
 * @description Checks if doCheckScriptCompile in ReplayAction compiles user script with trusted (unsandboxed) shell
 * @kind path-problem
 * @problem.severity error
 * @id java/replay-check-compile-trusted
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking

module ReplayCompileConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // getString / get calls on JSONObject/StaplerRequest in doCheckScriptCompile
    exists(MethodCall mc |
      mc.getEnclosingCallable().getDeclaringType().hasName("ReplayAction") and
      mc.getEnclosingCallable().hasName("doCheckScriptCompile") and
      mc.getMethod().hasName(["getString", "get", "getParameter"]) and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // Any GroovyShell/ClassLoader parse/evaluate call
    exists(MethodCall mc |
      mc.getMethod().hasName(["evaluate", "parse", "run", "runScript", "parseClass"]) and
      (
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyShell") or
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("groovy.lang", "GroovyClassLoader")
      ) and
      sink.asExpr() = mc.getArgument(0)
    )
    or
    // CpsFlowDefinition constructor
    exists(ClassInstanceExpr ce |
      ce.getConstructor().getDeclaringType().hasName("CpsFlowDefinition") and
      sink.asExpr() = ce.getArgument(0)
    )
  }
}

module ReplayCompileFlow = TaintTracking::Global<ReplayCompileConfig>;
import ReplayCompileFlow::PathGraph

