/**
 * @name forTrusted shell used with user-controlled script
 * @description Find if forTrusted() (unsandboxed) shell is used to parse/compile user scripts
 * @kind path-problem
 * @problem.severity error
 * @id java/for-trusted-with-user-script
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking

module TrustedShellConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    // forTrusted() call - creates unsandboxed shell
    exists(MethodCall mc |
      mc.getMethod().hasName("forTrusted") and
      mc.getMethod().getDeclaringType().hasName("CpsGroovyShellFactory") and
      source.asExpr() = mc
    )
  }

  predicate isSink(DataFlow::Node sink) {
    // parse() call on the shell
    exists(MethodCall mc |
      mc.getMethod().hasName(["parse", "doParse", "reparse", "evaluate", "run"]) and
      sink.asExpr() = mc.getQualifier()
    )
  }
}

module TrustedShellFlow = TaintTracking::Global<TrustedShellConfig>;
import TrustedShellFlow::PathGraph

from TrustedShellFlow::PathNode source, TrustedShellFlow::PathNode sink
where TrustedShellFlow::flowPath(source, sink)
select sink.getNode(), source, sink, "Trusted (unsandboxed) shell from $@ is used for script parsing.", source.getNode(), "forTrusted() call"

/**
 * @name EnvActionImpl - environment variable injection via user-controlled values
 * @description Check if user-controlled env vars can influence command execution
 * @kind path-problem
 * @problem.severity error
 * @id java/env-var-injection
 * @tags security
 *       external/cwe/cwe-078
 */

import java
import semmle.code.java.dataflow.TaintTracking
import semmle.code.java.dataflow.FlowSources

module EnvVarInjectionConfig implements DataFlow::ConfigSig {
  predicate isSource(DataFlow::Node source) {
    source instanceof RemoteFlowSource
  }

  predicate isSink(DataFlow::Node sink) {
    // EnvVars or environment-setting that may reach command execution
    exists(MethodCall mc |
      (
        mc.getMethod().hasName(["exec", "start"]) and
        mc.getMethod().getDeclaringType().getASupertype*().hasQualifiedName("java.lang", "Runtime")
      ) or (
        mc.getMethod().hasName(["start", "command"]) and
        mc.getMethod().getDeclaringType().hasQualifiedName("java.lang", "ProcessBuilder")
      ) and
      sink.asExpr() = mc.getAnArgument()
    )
    or
    // EnvActionImpl put / override
    exists(MethodCall mc |
      mc.getMethod().hasName(["put", "override", "overrideAll"]) and
      mc.getMethod().getDeclaringType().hasName("EnvActionImpl") and
      sink.asExpr() = mc.getAnArgument()
    )
  }
}

